function transformText(e,v){if(e==='text-base64')return btoa(unescape(encodeURIComponent(v)));if(e==='base64-text')return decodeURIComponent(escape(atob(v.trim())));if(e==='url-encode')return encodeURIComponent(v);if(e==='url-decode')return decodeURIComponent(v);if(e==='html-escape'){var t=d.createElement('div');t.textContent=v;return t.innerHTML}if(e==='html-unescape'){var q=d.createElement('textarea');q.innerHTML=v;return q.value}if(e==='json-pretty')return JSON.stringify(JSON.parse(v),null,2);if(e==='json-minify')return JSON.stringify(JSON.parse(v));if(e==='upper-lower')return v.toLowerCase();if(e==='lower-upper')return v.toUpperCase();if(e==='space-hyphen')return v.trim().replace(/\s+/g,'-');if(e==='line-comma')return v.split(/\r?\n/).map(function(s){return s.trim()}).filter(Boolean).join(', ');if(e==='srt-vtt')return 'WEBVTT\n\n'+v.replace(/(\d{2}:\d{2}:\d{2}),(\d{3})/g,'$1.$2');if(e==='vtt-srt')return v.replace(/^WEBVTT\s*/,'').replace(/(\d{2}:\d{2}:\d{2})\.(\d{3})/g,'$1,$2').trim();if(e==='srt-txt'||e==='vtt-txt')return v.replace(/^WEBVTT\s*/,'').replace(/^\d+\s*$/gm,'').replace(/\d{2}:\d{2}:\d{2}[,.]\d{3}\s+-->\s+\d{2}:\d{2}:\d{2}[,.]\d{3}.*$/gm,'').replace(/\n{3,}/g,'\n\n').trim();throw new Error('지원하지 않는 변환입니다.')}
